static int Dtool_Traverse_PythonThread(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  PythonThread *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_PythonThread, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_PythonThread(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_PythonThread._PyType && DtoolInstance_TYPE(self) == &Dtool_PythonThread) {
    DtoolProxy_PythonThread *proxy = (DtoolProxy_PythonThread *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

